  1→import React, { useState, useEffect } from 'react';
  2→import { Search, ShieldCheck, TrendingUp, Sparkles, Globe, Bot, BarChart3, CheckCircle } from 'lucide-react';
  3→
  4→const analysisSteps = [
  5→  { icon: Globe, label: 'Crawl du site web...', duration: 2000 },
  6→  { icon: Bot, label: 'Interrogation des IA (ChatGPT, Claude, Gemini, AI Overviews)...', duration: 3000 },
  7→  { icon: BarChart3, label: 'Analyse des 50+ critères AEO...', duration: 2500 },
  8→  { icon: CheckCircle, label: 'Génération du rapport...', duration: 1500 },
  9→];
 10→
 11→interface AnalyzeProps {
 12→  onAnalyze: (url: string) => void;
 13→  isAnalyzing: boolean;
 14→}
 15→
 16→const Analyze: React.FC<AnalyzeProps> = ({ onAnalyze, isAnalyzing }) => {
 17→  const [inputUrl, setInputUrl] = useState('');
 18→  const [currentStep, setCurrentStep] = useState(0);
 19→
 20→  useEffect(() => {
 21→    if (!isAnalyzing) { setCurrentStep(0); return; }
 22→    let step = 0;
 23→    setCurrentStep(0);
 24→    const timers: ReturnType<typeof setTimeout>[] = [];
 25→    let accumulated = 0;
 26→    analysisSteps.forEach((s, i) => {
 27→      if (i > 0) {
 28→        accumulated += analysisSteps[i - 1].duration;
 29→        timers.push(setTimeout(() => setCurrentStep(i), accumulated));
 30→      }
 31→    });
 32→    return () => timers.forEach(clearTimeout);
 33→  }, [isAnalyzing]);
 34→
 35→  const handleSubmit = (e: React.FormEvent) => {
 36→    e.preventDefault();
 37→    if (inputUrl && !isAnalyzing) {
 38→      onAnalyze(inputUrl);
 39→    }
 40→  };
 41→
 42→  return (
 43→    <div className="w-full px-4 min-h-[80vh] flex flex-col items-center justify-center animate-in fade-in duration-500">
 44→      
 45→      <div className="text-center mb-10 space-y-4">
 46→        <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/[0.04] border border-white/[0.08] text-purple-400 text-sm font-medium">
 47→          <Sparkles size={14} />
 48→          <span>Audit AEO & GEO Instantané</span>
 49→        </div>
 50→        <h1 className="text-4xl md:text-5xl font-sans font-bold text-white">
 51→          Analysez votre <span className="gradient-text">visibilité IA</span>
 52→        </h1>
 53→        <p className="text-xl text-gray-500 max-w-2xl mx-auto">
 54→          Découvrez comment les moteurs de réponse perçoivent votre contenu et obtenez un plan d'action pour être cité.
 55→        </p>
 56→      </div>
 57→
 58→      <div className="w-full max-w-3xl relative z-10">
 59→        <div className="absolute inset-0 bg-primary/20 blur-3xl rounded-full opacity-20 -z-10"></div>
 60→        <form onSubmit={handleSubmit}>
 61→          <div className="ninja-card p-8">
 62→            <div className="flex items-center gap-3">
 63→              <Search className="text-gray-500 shrink-0" size={24} />
 64→              <input
 65→                type="url"
 66→                required
 67→                placeholder="https://votre-site.com"
 68→                className="w-full bg-[#111111] border border-white/[0.08] rounded-xl focus:ring-1 focus:ring-purple-500/30 focus:border-purple-500/30 text-white placeholder-gray-500 text-lg px-4 py-4"
 69→                value={inputUrl}
 70→                onChange={(e) => setInputUrl(e.target.value)}
 71→                autoFocus
 72→              />
 73→              <button
 74→                type="submit"
 75→                disabled={isAnalyzing}
 76→                className={`btn-gradient px-8 py-4 shrink-0 transition-all transform hover:scale-105 ${isAnalyzing ? '!bg-gray-600 cursor-not-allowed opacity-60' : ''}`}
 77→              >
 78→                {isAnalyzing ? 'Analyse...' : 'Lancer l\'audit'}
 79→              </button>
 80→            </div>
 81→          </div>
 82→        </form>
 83→        
 84→        {!isAnalyzing && (
 85→          <div className="flex justify-center gap-8 mt-8 text-sm text-gray-500">
 86→            <span className="flex items-center gap-2"><ShieldCheck size={16} className="text-purple-400"/> Analyse Sécurisée</span>
 87→            <span className="flex items-center gap-2"><TrendingUp size={16} className="text-purple-400"/> +50 Critères GEO</span>
 88→          </div>
 89→        )}
 90→
 91→        {isAnalyzing && (
 92→          <div className="mt-8 w-full max-w-md mx-auto space-y-3 animate-in fade-in duration-300">
 93→            {analysisSteps.map((step, i) => {
 94→              const StepIcon = step.icon;
 95→              const isActive = i === currentStep;
 96→              const isDone = i < currentStep;
 97→              return (
 98→                <div key={i} className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-500 ${
 99→                  isActive ? 'bg-purple-500/10 border border-purple-500/20' : isDone ? 'bg-white/[0.02] border border-white/[0.04]' : 'opacity-40 border border-transparent'
100→                }`}>
101→                  <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 transition-all duration-300 ${
102→                    isDone ? 'bg-emerald-500/20' : isActive ? 'bg-purple-500/20' : 'bg-white/[0.04]'
103→                  }`}>
104→                    {isDone ? <CheckCircle size={16} className="text-emerald-400" /> : <StepIcon size={16} className={isActive ? 'text-purple-400 animate-pulse' : 'text-gray-600'} />}
105→                  </div>
106→                  <span className={`text-sm font-medium transition-colors duration-300 ${isDone ? 'text-emerald-400' : isActive ? 'text-purple-300' : 'text-gray-600'}`}>{step.label}</span>
107→                  {isActive && <div className="ml-auto w-4 h-4 border-2 border-purple-400 border-t-transparent rounded-full animate-spin" />}
108→                </div>
109→              );
110→            })}
111→            <div className="mt-4 w-full h-1.5 bg-white/[0.06] rounded-full overflow-hidden">
112→              <div className="h-full bg-gradient-to-r from-purple-500 to-violet-500 rounded-full transition-all duration-1000 ease-out" style={{ width: `${((currentStep + 1) / analysisSteps.length) * 100}%` }} />
113→            </div>
114→          </div>
115→        )}
116→      </div>
117→
118→    </div>
119→  );
120→};
121→
122→export default Analyze;

  1→import React, { useMemo, useState } from 'react';
  2→import { AnalysisResult, CategoryScore, GeneratedSolution, User } from '../types';
  3→import CategoryCard from '../components/CategoryCard';
  4→import EngineBreakdown from '../components/EngineBreakdown';
  5→import { calculateEngineScores } from '../lib/engine-score-calculator';
  6→import { mapAnalysisResults } from '../lib/criteria-mapper';
  7→import { Info, Download, Share2, ScanLine, CheckCircle2, AlertTriangle, XCircle } from 'lucide-react';
  8→import html2canvas from 'html2canvas';
  9→import jsPDF from 'jspdf';
 10→
 11→interface Props {
 12→  data: AnalysisResult;
 13→  onBack: () => void;
 14→  user: User | null;
 15→  onDeductCredits: (amount: number) => boolean;
 16→  onSaveSolution: (analysisId: string, recId: string, solution: GeneratedSolution) => void;
 17→  initialTab?: 'details' | 'archives' | 'overview'; // Expanded type to include overview
 18→  onNewAnalysis?: () => void;
 19→}
 20→
 21→export const Results: React.FC<Props> = ({ data, onBack, user, onDeductCredits, onSaveSolution, onNewAnalysis }) => {
 22→  const [isExporting, setIsExporting] = useState(false);
 23→
 24→  const categoryScores = Object.values(data.categories) as CategoryScore[];
 25→
 26→  const engineScores = useMemo(() => {
 27→    const criteriaResults = mapAnalysisResults(data);
 28→    return calculateEngineScores(criteriaResults);
 29→  }, [data]);
 30→
 31→  const handleDownloadPDF = async () => {
 32→    const element = document.getElementById('full-pdf-report');
 33→    if (!element) return;
 34→
 35→    setIsExporting(true);
 36→    try {
 37→      // Wait a moment for the hidden div to render properly
 38→      await new Promise(resolve => setTimeout(resolve, 500));
 39→
 40→      const canvas = await html2canvas(element, {
 41→        scale: 2,
 42→        useCORS: true,
 43→        logging: false,
 44→        windowWidth: 1000 // Force width to match container style
 45→      });
 46→
 47→      const imgData = canvas.toDataURL('image/jpeg', 0.95);
 48→      const pdf = new jsPDF({
 49→        orientation: 'portrait',
 50→        unit: 'mm',
 51→        format: 'a4'
 52→      });
 53→
 54→      const pdfWidth = pdf.internal.pageSize.getWidth();
 55→      const pdfHeight = pdf.internal.pageSize.getHeight();
 56→      const imgWidth = pdfWidth;
 57→      const imgHeight = (canvas.height * imgWidth) / canvas.width;
 58→      
 59→      let heightLeft = imgHeight;
 60→      let position = 0;
 61→
 62→      // First page
 63→      pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight);
 64→      heightLeft -= pdfHeight;
 65→
 66→      // Subsequent pages if content overflows
 67→      while (heightLeft > 0) {
 68→        position = heightLeft - imgHeight;
 69→        pdf.addPage();
 70→        pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight);
 71→        heightLeft -= pdfHeight;
 72→      }
 73→      
 74→      const hostname = new URL(data.url).hostname;
 75→      pdf.save(`Audit_AEO_${hostname}_${new Date().toISOString().split('T')[0]}.pdf`);
 76→    } catch (err) {
 77→      console.error('PDF Export failed', err);
 78→      alert('Erreur lors de la génération du PDF.');
 79→    } finally {
 80→      setIsExporting(false);
 81→    }
 82→  };
 83→
 84→  const handleShare = async () => {
 85→    const shareData = {
 86→      title: 'Rapport AEO - CitedBy.ai',
 87→      text: `Découvrez l'analyse AEO pour ${data.url} sur CitedBy.ai`,
 88→      url: window.location.href,
 89→    };
 90→
 91→    try {
 92→      if (navigator.share) {
 93→        await navigator.share(shareData);
 94→      } else {
 95→        await navigator.clipboard.writeText(window.location.href);
 96→        alert('Lien du rapport copié dans le presse-papier !');
 97→      }
 98→    } catch (err) {
 99→      console.error('Share failed', err);
100→    }
101→  };
102→
103→  return (
104→    <div className="w-full px-4 pb-20 pt-6 relative">
105→      
106→      {/* Header */}
107→      <div className="flex flex-col md:flex-row items-start md:items-center justify-between mb-8 gap-6 pt-6">
108→        <div>
109→          <h1 className="text-3xl font-sans font-bold text-white mb-2"><span className="gradient-text">{new URL(data.url).hostname}</span></h1>
110→          <p className="text-gray-400 text-sm">Analysé le {new Date(data.timestamp).toLocaleDateString()} à {new Date(data.timestamp).toLocaleTimeString()}</p>
111→        </div>
112→        
113→        {onNewAnalysis && (
114→            <button 
115→                onClick={onNewAnalysis}
116→                className="btn-gradient flex items-center gap-2 px-6 py-3 text-white font-bold transition-all hover:scale-105"
117→            >
118→                <ScanLine size={18} /> Lancer un nouvel audit
119→            </button>
120→        )}
121→      </div>
122→
123→      {/* Content - Single View (Details) */}
124→      <div className="min-h-[500px]">
125→          <div className="space-y-6 animate-in fade-in">
126→            <div className="flex justify-between items-center mb-4">
127→               <h3 className="text-lg font-sans font-semibold text-white">Analyse <span className="gradient-text">détaillée</span> par catégorie</h3>
128→               <div className="flex gap-3">
129→                  <button 
130→                    onClick={handleShare}
131→                    className="flex items-center gap-2 px-5 py-2.5 border border-white/[0.08] bg-white/[0.04] hover:bg-white/[0.08] rounded-full text-sm text-gray-300 transition-colors"
132→                  >
133→                    <Share2 size={16} /> Partager
134→                  </button>
135→                  <button 
136→                    onClick={handleDownloadPDF}
137→                    disabled={isExporting}
138→                    className="flex items-center gap-2 px-5 py-2.5 border border-white/[0.08] bg-white/[0.04] hover:bg-white/[0.08] rounded-full text-sm text-purple-400 font-medium transition-colors"
139→                  >
140→                    {isExporting ? (
141→                        <>
142→                            <div className="animate-spin h-4 w-4 border-2 border-primary border-t-transparent rounded-full"></div>
143→                            Génération...
144→                        </>
145→                    ) : (
146→                        <>
147→                            <Download size={16} /> Générer PDF Complet
148→                        </>
149→                    )}
150→                  </button>
151→               </div>
152→            </div>
153→
154→            {/* Engine-specific scores breakdown */}
155→            <EngineBreakdown engineScores={engineScores} />
156→
157→            <div className="grid md:grid-cols-2 gap-6">
158→              {categoryScores.map((cat, i) => (
159→                <CategoryCard key={i} category={cat} />
160→              ))}
161→            </div>
162→
163→            {/* --- PROFESSIONAL PDF REPORT CONTAINER (HIDDEN) --- */}
164→            <div 
165→              id="full-pdf-report" 
166→              className="bg-white text-black font-sans"
167→              style={{
168→                position: 'absolute',
169→                top: 0,
170→                left: '-9999px',
171→                width: '1000px', 
172→                padding: '60px',
173→              }}
174→            >
175→              {/* PAGE 1: COVER */}
176→              <div className="flex flex-col h-[1300px] relative border-b-2 border-gray-100 mb-10 pb-10">
177→                  {/* Header Logo */}
178→                  <div className="flex justify-between items-center mb-20">
179→                      <div className="flex items-center gap-3">
180→                          <div className="w-12 h-12 rounded bg-[#a855f7] flex items-center justify-center text-white font-serif font-bold text-3xl">C</div>
181→                          <span className="font-serif text-3xl font-bold text-gray-900">CitedBy.ai</span>
182→                      </div>
183→                      <div className="text-right">
184→                          <p className="text-gray-500 text-sm">Rapport d'Audit AEO</p>
185→                          <p className="text-gray-900 font-bold">{new Date(data.timestamp).toLocaleDateString()}</p>
186→                      </div>
187→                  </div>
188→
189→                  {/* Title Section */}
190→                  <div className="text-center mt-20 mb-20">
191→                      <h1 className="text-5xl font-serif font-bold text-gray-900 mb-6 tracking-tight">Audit de Visibilité Générative</h1>
192→                      <p className="text-2xl text-gray-500">{new URL(data.url).hostname}</p>
193→                  </div>
194→
195→                  {/* Score Hero */}
196→                  <div className="flex justify-center mb-20">
197→                      <div className="relative w-64 h-64 flex items-center justify-center">
198→                          {/* We recreate a static SVG ring for PDF to avoid animation glitches */}
199→                          <svg viewBox="0 0 100 100" className="w-full h-full transform -rotate-90">
200→                              <circle cx="50" cy="50" r="45" fill="none" stroke="#f3f4f6" strokeWidth="8" />
201→                              <circle 
202→                                cx="50" 
203→                                cy="50" 
204→                                r="45" 
205→                                fill="none" 
206→                                stroke={data.globalScore >= 80 ? "#a855f7" : data.globalScore >= 50 ? "#c084fc" : "#ef4444"}
207→                                strokeWidth="8" 
208→                                strokeDasharray={`${(data.globalScore / 100) * 283} 283`}
209→                                strokeLinecap="round"
210→                              />
211→                          </svg>
212→                          <div className="absolute flex flex-col items-center">
213→                              <span className="text-6xl font-bold text-gray-900">{data.globalScore}</span>
214→                              <span className="text-sm font-bold text-gray-400 uppercase tracking-widest mt-2">Score Global</span>
215→                          </div>
216→                      </div>
217→                  </div>
218→
219→                  {/* Executive Summary */}
220→                  <div className="bg-gray-50 p-8 rounded-2xl border border-gray-200 mt-auto mb-10">
221→                      <h3 className="font-bold text-gray-900 text-lg mb-4 flex items-center gap-2">
222→                          <Info size={20} className="text-[#a855f7]" /> Synthèse de l'analyste
223→                      </h3>
224→                      <p className="text-gray-600 leading-relaxed mb-4">
225→                          L'analyse de <strong>{new URL(data.url).hostname}</strong> révèle une probabilité de citation par les assistants IA de <strong>{data.aiCitation.probability}%</strong>. 
226→                          {data.globalScore < 50 
227→                              ? " L'entité manque actuellement de signaux structurés pour être correctement identifiée par les Knowledge Graphs."
228→                              : " L'entité possède une base solide mais nécessite des optimisations sémantiques pour garantir la primauté de la réponse."}
229→                      </p>
230→                      <div className="grid grid-cols-3 gap-6 pt-4 border-t border-gray-200">
231→                          <div>
232→                              <p className="text-xs text-gray-500 uppercase font-bold">Confiance</p>
233→                              <p className="text-lg font-bold text-gray-900">{data.categories['trust']?.score || 0}/100</p>
234→                          </div>
235→                          <div>
236→                              <p className="text-xs text-gray-500 uppercase font-bold">Technique</p>
237→                              <p className="text-lg font-bold text-gray-900">{data.categories['technical']?.score || 0}/100</p>
238→                          </div>
239→                          <div>
240→                              <p className="text-xs text-gray-500 uppercase font-bold">Autorité</p>
241→                              <p className="text-lg font-bold text-gray-900">{data.categories['entity']?.score || 0}/100</p>
242→                          </div>
243→                      </div>
244→                  </div>
245→              </div>
246→
247→              {/* PAGE 2+: RAPPORT D'AUDIT DÉTAILLÉ (pas de plan d'action) */}
248→              <div style={{ display: 'flex', flexDirection: 'column' }}>
249→                  {/* Section Header */}
250→                  <div style={{ marginBottom: '32px', borderBottom: '3px solid #a855f7', paddingBottom: '12px' }}>
251→                      <h2 style={{ fontSize: '24px', fontWeight: 700, color: '#111827', margin: '0 0 4px 0', fontFamily: 'Georgia, serif' }}>
252→                          Rapport d'Audit Détaillé
253→                      </h2>
254→                      <p style={{ fontSize: '13px', color: '#6b7280', margin: 0 }}>
255→                          Analyse de {categoryScores.length} catégories — {categoryScores.reduce((sum, c) => sum + c.items.length, 0)} critères évalués
256→                      </p>
257→                  </div>
258→
259→                  {/* TABLEAU RÉCAPITULATIF */}
260→                  <table style={{ width: '100%', borderCollapse: 'collapse', marginBottom: '40px', borderRadius: '8px', overflow: 'hidden', border: '1px solid #e5e7eb' }}>
261→                      <thead>
262→                          <tr style={{ backgroundColor: '#f8f5ff' }}>
263→                              <th style={{ padding: '12px 16px', textAlign: 'left', fontSize: '11px', fontWeight: 700, color: '#6b7280', textTransform: 'uppercase', letterSpacing: '0.05em', borderBottom: '2px solid #d8b4fe' }}>Catégorie</th>
264→                              <th style={{ padding: '12px 16px', textAlign: 'center', fontSize: '11px', fontWeight: 700, color: '#6b7280', textTransform: 'uppercase', letterSpacing: '0.05em', borderBottom: '2px solid #d8b4fe', width: '80px' }}>Score</th>
265→                              <th style={{ padding: '12px 16px', textAlign: 'center', fontSize: '11px', fontWeight: 700, color: '#16a34a', textTransform: 'uppercase', letterSpacing: '0.05em', borderBottom: '2px solid #d8b4fe', width: '70px' }}>Conforme</th>
266→                              <th style={{ padding: '12px 16px', textAlign: 'center', fontSize: '11px', fontWeight: 700, color: '#d97706', textTransform: 'uppercase', letterSpacing: '0.05em', borderBottom: '2px solid #d8b4fe', width: '70px' }}>Alerte</th>
267→                              <th style={{ padding: '12px 16px', textAlign: 'center', fontSize: '11px', fontWeight: 700, color: '#dc2626', textTransform: 'uppercase', letterSpacing: '0.05em', borderBottom: '2px solid #d8b4fe', width: '70px' }}>Échec</th>
268→                          </tr>
269→                      </thead>
270→                      <tbody>
271→                          {categoryScores.map((cat, i) => {
272→                              const successCount = cat.items.filter(item => item.status === 'success').length;
273→                              const warningCount = cat.items.filter(item => item.status === 'warning').length;
274→                              const errorCount = cat.items.filter(item => item.status === 'error').length;
275→                              return (
276→                                  <tr key={i} style={{ backgroundColor: i % 2 === 0 ? '#ffffff' : '#fafafa' }}>
277→                                      <td style={{ padding: '10px 16px', fontSize: '13px', fontWeight: 600, color: '#111827', borderBottom: '1px solid #f3f4f6' }}>{cat.name}</td>
278→                                      <td style={{ padding: '10px 16px', textAlign: 'center', borderBottom: '1px solid #f3f4f6' }}>
279→                                          <span style={{
280→                                              display: 'inline-block', padding: '2px 14px', borderRadius: '12px', fontSize: '13px', fontWeight: 700,
281→                                              backgroundColor: cat.score >= 80 ? '#f0fdf4' : cat.score >= 50 ? '#faf5ff' : '#fef2f2',
282→                                              color: cat.score >= 80 ? '#16a34a' : cat.score >= 50 ? '#7c3aed' : '#dc2626',
283→                                          }}>{cat.score}</span>
284→                                      </td>
285→                                      <td style={{ padding: '10px 16px', textAlign: 'center', fontSize: '13px', fontWeight: 600, color: '#16a34a', borderBottom: '1px solid #f3f4f6' }}>{successCount}</td>
286→                                      <td style={{ padding: '10px 16px', textAlign: 'center', fontSize: '13px', fontWeight: 600, color: '#d97706', borderBottom: '1px solid #f3f4f6' }}>{warningCount}</td>
287→                                      <td style={{ padding: '10px 16px', textAlign: 'center', fontSize: '13px', fontWeight: 600, color: '#dc2626', borderBottom: '1px solid #f3f4f6' }}>{errorCount}</td>
288→                                  </tr>
289→                              );
290→                          })}
291→                          {/* Total row */}
292→                          <tr style={{ backgroundColor: '#f8f5ff', borderTop: '2px solid #d8b4fe' }}>
293→                              <td style={{ padding: '10px 16px', fontSize: '13px', fontWeight: 700, color: '#111827' }}>Total</td>
294→                              <td style={{ padding: '10px 16px', textAlign: 'center' }}>
295→                                  <span style={{ display: 'inline-block', padding: '2px 14px', borderRadius: '12px', fontSize: '13px', fontWeight: 700, backgroundColor: '#a855f7', color: '#ffffff' }}>{data.globalScore}</span>
296→                              </td>
297→                              <td style={{ padding: '10px 16px', textAlign: 'center', fontSize: '13px', fontWeight: 700, color: '#16a34a' }}>{categoryScores.reduce((s, c) => s + c.items.filter(i => i.status === 'success').length, 0)}</td>
298→                              <td style={{ padding: '10px 16px', textAlign: 'center', fontSize: '13px', fontWeight: 700, color: '#d97706' }}>{categoryScores.reduce((s, c) => s + c.items.filter(i => i.status === 'warning').length, 0)}</td>
299→                              <td style={{ padding: '10px 16px', textAlign: 'center', fontSize: '13px', fontWeight: 700, color: '#dc2626' }}>{categoryScores.reduce((s, c) => s + c.items.filter(i => i.status === 'error').length, 0)}</td>
300→                          </tr>
301→                      </tbody>
302→                  </table>
303→
304→                  {/* TABLEAUX DÉTAILLÉS PAR CATÉGORIE */}
305→                  {categoryScores.map((cat, i) => (
306→                      <div key={i} style={{ marginBottom: '28px' }}>
307→                          {/* Category Header Bar */}
